def validate(strings):
    assert len(strings) == 25, len(strings)
    for i, s in enumerate(strings):
        bad = sorted({c for c in s if c.isascii() and c.isalpha()})
        if bad:
            raise SystemExit(f"String {i+1} has Latin {bad}: {s[:100]}...")

